import java.util.*;class BinarySearch3{public static void main(String[] a){Scanner s=new Scanner(System.in);int r=s.nextInt(),c=s.nextInt();int[][] m=new int[r][c];for(int i=0;i<r;i++)for(int j=0;j<c;j++)m[i][j]=s.nextInt();int t=s.nextInt();int l=0,h=r*c-1;while(l<=h){int mid=(l+h)/2;int val=m[mid/c][mid%c];if(val==t){System.out.println(true);return;}else if(val<t)l=mid+1;else h=mid-1;}System.out.println(false);}}